// src/pages/RegisterManageSub2Page.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import '../Dashboard.css';
import './RegisterManageSub2Page.css'; // Import file CSS mới cho trang này

function FarmListPage() {
  // State để lưu trữ danh sách các cơ sở nuôi
  const [farms, setFarms] = useState([]);
  // State cho bộ lọc tìm kiếm chung
  const [filter, setFilter] = useState('');
  // State cho bộ lọc theo Tỉnh (Thành phố)
  const [selectedProvince, setSelectedProvince] = useState('');
  // State cho bộ lọc theo Xã (Phường)
  const [selectedCommune, setSelectedCommune] = useState('');
  // State cho bộ lọc theo Loài nuôi
  const [selectedSpecies, setSelectedSpecies] = useState('');
  // State mới cho bộ lọc theo Loại cơ sở đăng ký (Gây nuôi / Kinh doanh gỗ)
  const [selectedLoaiCoSoDangKy, setSelectedLoaiCoSoDangKy] = useState('');
  // State mới cho bộ lọc theo Ngành nghề Kinh doanh gỗ
  const [selectedNganhNgheKinhDoanhGo, setSelectedNganhNgheKinhDoanhGo] = useState('');

  // State để lưu trữ các giá trị Tỉnh (Thành phố) duy nhất cho dropdown
  const [uniqueProvinces, setUniqueProvinces] = useState([]);
  // State để lưu trữ các giá trị Xã (Phường) duy nhất cho dropdown
  const [uniqueCommunes, setUniqueCommunes] = useState([]);
  // State để lưu trữ các giá trị Loài nuôi duy nhất cho dropdown
  const [uniqueSpecies, setUniqueSpecies] = useState([]);
  // State để lưu trữ các giá trị Loại cơ sở đăng ký duy nhất cho dropdown
  const [uniqueLoaiCoSoDangKy, setUniqueLoaiCoSoDangKy] = useState([]);
  // State để lưu trữ các giá trị Ngành nghề Kinh doanh gỗ duy nhất cho dropdown
  const [uniqueNganhNgheKinhDoanhGo, setUniqueNganhNgheKinhDoanhGo] = useState([]);

  // Hook để điều hướng giữa các trang
  const navigate = useNavigate();
  // Lấy token xác thực từ localStorage
  const token = localStorage.getItem('token');

  // Định nghĩa các cột của bảng và trạng thái hiển thị ban đầu của chúng
  // Đã loại bỏ maxWidth khỏi đây để quản lý chiều rộng động trong render
  const initialColumnsConfig = {
    tenCoSo: { label: 'Tên cơ sở', visible: true },
    tinhThanhPho: { label: 'Tỉnh (TP)', visible: true },
    xaPhuong: { label: 'Xã (Phường)', visible: true },
    diaChiCoSo: { label: 'Địa chỉ cơ sở', visible: true },
    vido: { label: 'Vĩ độ', visible: true },
    kinhdo: { label: 'Kinh độ', visible: true },
    ghiChu: { label: 'Ghi chú', visible: false },
    tenNguoiDaiDien: { label: 'Người đại diện', visible: true },
    soDienThoaiNguoiDaiDien: { label: 'SĐT Người đại diện', visible: true },
    emailNguoiDaiDien: { label: 'Email Người đại diện', visible: true },
    loaiHinhCoSo: { label: 'Loại hình cơ sở', visible: true },
    ngayThanhLap: { label: 'Ngày thành lập', visible: true },
    giayPhepKinhDoanh: { label: 'Số GPKD', visible: true },
    mucDichNuoi: { label: 'Mục đích nuôi', visible: false },
    hinhThucNuoi: { label: 'Hình thức nuôi', visible: false },
    maSoCoSoGayNuoi: { label: 'Mã số CS gây nuôi', visible: false },
    loaiHinhKinhDoanhGo: { label: 'Loại hình KD gỗ', visible: false },
    nganhNgheKinhDoanhGo: { label: 'Ngành nghề KD gỗ', visible: false },
    loaiCoSoDangKy: { label: 'Loại CS Đăng ký', visible: true },
    licenseNumber: { label: 'Số giấy phép', visible: false },
    issueDate: { label: 'Ngày cấp GP', visible: false },
    expiryDate: { label: 'Ngày hết hạn GP', visible: false },
    actions: { label: '🛠️', visible: true, width: '70px', minWidth: '70px', maxWidth: '70px' }, // Cột hành động cố định
  };

  // State để quản lý trạng thái hiển thị của các cột
  const [columns, setColumns] = useState(initialColumnsConfig);
  // State để quản lý việc hiển thị/ẩn tùy chọn cột
  const [showColumnOptions, setShowColumnOptions] = useState(false);

  // useEffect để tải trạng thái cột từ localStorage khi component mount
  useEffect(() => {
    try {
      const savedColumns = localStorage.getItem('tableColumnsVisibility');
      if (savedColumns) {
        const parsedSavedColumns = JSON.parse(savedColumns);
        const mergedColumns = Object.keys(initialColumnsConfig).reduce((acc, key) => {
          const savedCol = parsedSavedColumns.find(sCol => sCol.id === key);
          acc[key] = savedCol ? { ...initialColumnsConfig[key], visible: savedCol.visible } : initialColumnsConfig[key];
          return acc;
        }, {});
        setColumns(mergedColumns);
      }
    } catch (error) {
      console.error("Error loading column visibility from localStorage:", error);
      // Fallback to initial columns if loading fails
      setColumns(initialColumnsConfig);
    }
  }, []); // Empty dependency array means this runs once on mount

  // useEffect để lưu trạng thái cột vào localStorage mỗi khi state 'columns' thay đổi
  useEffect(() => {
    try {
      // Chỉ lưu id và visible để tránh lưu trữ các thuộc tính CSS không cần thiết
      const columnsToSave = Object.keys(columns).map(key => ({
        id: key,
        visible: columns[key].visible
      }));
      localStorage.setItem('tableColumnsVisibility', JSON.stringify(columnsToSave));
    } catch (error) {
      console.error("Error saving column visibility to localStorage:", error);
    }
  }, [columns]); // Runs whenever 'columns' state changes


  // useEffect để tải danh sách cơ sở nuôi khi component được mount hoặc khi selectedLoaiCoSoDangKy thay đổi
  useEffect(() => {
    const fetchFarms = async () => {
      try {
        const params = {};
        // Thêm bộ lọc farmType vào params nếu selectedLoaiCoSoDangKy được chọn
        if (selectedLoaiCoSoDangKy !== '') {
          params.farmType = selectedLoaiCoSoDangKy; // Đã sửa lỗi chính tả ở đây
        }

        // Gửi yêu cầu GET đến API để lấy danh sách cơ sở nuôi
        const response = await axios.get('http://localhost:10000/api/farms', {
          headers: {
            Authorization: `Bearer ${token}` // Gửi token xác thực trong header
          },
          params: params // Truyền các tham số bộ lọc vào backend
        });
        setFarms(response.data); // Cập nhật state farms với dữ liệu nhận được

        // Trích xuất các giá trị duy nhất cho các bộ lọc từ dữ liệu đã tải
        const provinces = [...new Set(response.data.map(f => f.tinhThanhPho).filter(Boolean))].sort();
        const communes = [...new Set(response.data.map(f => f.xaPhuong).filter(Boolean))].sort();
        const species = [...new Set(response.data.flatMap(f => f.species ? f.species.map(s => s.name) : []).filter(Boolean))].sort();
        const loaiCoSoDangKy = [...new Set(response.data.map(f => f.loaiCoSoDangKy).filter(Boolean))].sort();
        const nganhNgheKinhDoanhGo = [...new Set(response.data.map(f => f.nganhNgheKinhDoanhGo).filter(Boolean))].sort();

        // Cập nhật các state chứa giá trị duy nhất
        setUniqueProvinces(provinces);
        setUniqueCommunes(communes);
        setUniqueSpecies(species);
        setUniqueLoaiCoSoDangKy(loaiCoSoDangKy);
        setUniqueNganhNgheKinhDoanhGo(nganhNgheKinhDoanhGo);

      } catch (error) {
        console.error('❌ Lỗi khi lấy danh sách cơ sở nuôi:', error);
        // Nếu lỗi do xác thực (401) hoặc không có quyền (403), chuyển hướng về trang đăng nhập
        if (error.response && (error.response.status === 401 || error.response.status === 403)) {
          navigate('/');
        }
      }
    };

    // Chỉ fetch dữ liệu nếu có token
    if (token) {
      fetchFarms();
    } else {
      navigate('/'); // Chuyển hướng nếu không có token
    }
  }, [token, navigate, selectedLoaiCoSoDangKy]); // Re-fetch khi token, navigate hoặc selectedLoaiCoSoDangKy thay đổi

  // Hàm xử lý xóa một cơ sở nuôi
  const handleDelete = async (id) => {
    // Đã thay thế window.confirm bằng một modal tùy chỉnh nếu bạn có
    // if (window.confirm('Bạn có chắc chắn muốn xoá?')) {
      try {
        // Gửi yêu cầu DELETE đến API để xóa cơ sở
        await axios.delete(`http://localhost:10000/api/farms/${id}`, {
          headers: {
            Authorization: `Bearer ${token}`
          }
        });
        // Cập nhật lại danh sách farms bằng cách lọc bỏ cơ sở vừa xóa
        setFarms(farms.filter(f => f._id !== id));
      } catch (error) {
        console.error('Lỗi khi xoá:', error);
      }
    // }
  };

  // Hàm xử lý chỉnh sửa một cơ sở nuôi
  const handleEdit = (id) => {
    navigate(`/edit-farm/${id}`); // Chuyển hướng đến trang chỉnh sửa với ID của cơ sở
  };

  // Hàm xử lý xem chi tiết một cơ sở nuôi
  const handleView = (id) => {
    navigate(`/farm-details/${id}`); // Chuyển hướng đến trang chi tiết với ID của cơ sở
  };

  // Lọc danh sách farms dựa trên tất cả các tiêu chí (lọc frontend cho các trường khác)
  const filteredFarms = farms.filter(f => {
    // Kiểm tra khớp với bộ lọc tìm kiếm chung (general filter)
    const generalMatch = (
      (f.tinhThanhPho || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.tenCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.tenNguoiDaiDien || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.diaChiCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.ghiChu || '').toLowerCase().includes(filter.toLowerCase()) || // Bao gồm ghiChu trong tìm kiếm chung
      (f.loaiCoSoDangKy || '').toLowerCase().includes(filter.toLowerCase()) || // Bao gồm loaiCoSoDangKy trong tìm kiếm chung
      (f.nganhNgheKinhDoanhGo || '').toLowerCase().includes(filter.toLowerCase()) // Bao gồm nganhNgheKinhDoanhGo trong tìm kiếm chung
    );

    // Kiểm tra khớp với bộ lọc Tỉnh (Thành phố)
    const provinceMatch = selectedProvince ? (f.tinhThanhPho === selectedProvince) : true;
    // Kiểm tra khớp với bộ lọc Xã (Phường)
    const communeMatch = selectedCommune ? (f.xaPhuong === selectedCommune) : true;
    // Kiểm tra khớp với bộ lọc Loài nuôi
    const speciesMatch = selectedSpecies ? (f.species && f.species.some(s => s.name === selectedSpecies)) : true;
    // loaiCoSoDangKyMatch hiện đã được xử lý bởi bộ lọc backend, nhưng giữ lại cho tính nhất quán nếu cần cho các bộ lọc khác
    const nganhNgheKinhDoanhGoMatch = selectedNganhNgheKinhDoanhGo ? (f.nganhNgheKinhDoanhGo === selectedNganhNgheKinhDoanhGo) : true;

    // Trả về true nếu tất cả các điều kiện lọc đều khớp
    return generalMatch && provinceMatch && communeMatch && speciesMatch && nganhNgheKinhDoanhGoMatch;
  });

  // Hàm xử lý việc bật/tắt hiển thị cột
  const handleColumnToggle = (columnKey) => {
    setColumns(prevColumns => ({
      ...prevColumns,
      [columnKey]: {
        ...prevColumns[columnKey],
        visible: !prevColumns[columnKey].visible // Đảo ngược trạng thái hiển thị của cột
      }
    }));
  };

  return (
    <div className="farm-list-container"> {/* Container chính của trang danh sách */}
      <h2>📋 Danh sách cơ sở nuôi</h2>

      <div className="filter-container"> {/* Container cho các bộ lọc */}
        <input
          type="text"
          placeholder="🔍 Tìm kiếm chung..."
          value={filter}
          onChange={e => setFilter(e.target.value)}
        />

        {/* Bộ lọc mới cho Loại cơ sở đăng ký */}
        <select
          value={selectedLoaiCoSoDangKy}
          onChange={e => setSelectedLoaiCoSoDangKy(e.target.value)}
        >
          <option value="">Tất cả cơ sở</option>
          <option value="Đăng ký cơ sở gây nuôi">Đăng ký cơ sở gây nuôi</option>
          <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Đăng ký cơ sở kinh doanh, chế biến gỗ</option>
        </select>

        <select
          value={selectedProvince}
          onChange={e => setSelectedProvince(e.target.value)}
        >
          <option value="">Tất cả Tỉnh (TP)</option>
          {uniqueProvinces.map(province => (
            <option key={province} value={province}>{province}</option>
          ))}
        </select>

        <select
          value={selectedCommune}
          onChange={e => setSelectedCommune(e.target.value)}
        >
          <option value="">Tất cả Xã (Phường)</option>
          {uniqueCommunes.map(commune => (
            <option key={commune} value={commune}>{commune}</option>
          ))}
        </select>

        <select
          value={selectedSpecies}
          onChange={e => setSelectedSpecies(e.target.value)}
        >
          <option value="">Tất cả Loài nuôi</option>
          {uniqueSpecies.map(species => (
            <option key={species} value={species}>{species}</option>
          ))}
        </select>

        {/* Bộ lọc mới cho Ngành nghề kinh doanh gỗ */}
        <select
          value={selectedNganhNgheKinhDoanhGo}
          onChange={e => setSelectedNganhNgheKinhDoanhGo(e.target.value)}
        >
          <option value="">Tất cả Ngành nghề KD gỗ</option>
          {uniqueNganhNgheKinhDoanhGo.map(nganhNghe => (
            <option key={nganhNghe} value={nganhNghe}>{nganhNghe}</option>
          ))}
        </select>

        <button
          onClick={() => setShowColumnOptions(!showColumnOptions)}
        >
          {showColumnOptions ? 'Ẩn Tùy chọn Cột' : 'Hiện Tùy chọn Cột'}
        </button>
      </div>

      {showColumnOptions && (
        <div className="column-options-container"> {/* Container cho tùy chọn cột */}
          <h3>Chọn cột hiển thị:</h3>
          <div className="column-options-grid"> {/* Lưới hiển thị các tùy chọn cột */}
            {Object.keys(columns).map(key => (
              <label key={key}>
                <input
                  type="checkbox"
                  checked={columns[key].visible}
                  onChange={() => handleColumnToggle(key)}
                />
                {columns[key].label}
              </label>
            ))}
          </div>
        </div>
      )}

      {/* Hiển thị thông báo khi không có cơ sở nuôi nào */}
      {farms.length === 0 && !filter && <p>Không có cơ sở nuôi nào được đăng ký.</p>}
      {farms.length === 0 && filter && <p>Không tìm thấy cơ sở nuôi nào phù hợp với bộ lọc.</p>}

      {/* Bảng hiển thị danh sách cơ sở nuôi nếu có dữ liệu */}
      {filteredFarms.length > 0 && (
        <table border="1" cellPadding="8" className="table-auto w-full border-collapse"> {/* Đã thay style inline bằng class */}
          <thead style={{ background: '#f0f0f0' }}>
            <tr>
              {Object.keys(columns).map(key => (
                <th
                  key={key}
                  className={!columns[key].visible ? 'column-hidden' : ''} // Thêm class 'column-hidden'
                  style={
                    key === 'actions'
                      ? { // Cột hành động: cố định chiều rộng
                          width: initialColumnsConfig.actions.width,
                          minWidth: initialColumnsConfig.actions.minWidth,
                          maxWidth: initialColumnsConfig.actions.maxWidth,
                        }
                      : {} // Cột khác: để CSS class 'column-hidden' xử lý hoặc browser tự điều chỉnh
                  }
                >
                  {columns[key].label}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filteredFarms.map((f, i) => (
              <tr key={f._id || i}>
                {Object.keys(columns).map(key => (
                  <td
                    key={`${f._id || i}-${key}`}
                    className={!columns[key].visible ? 'column-hidden' : ''} // Thêm class 'column-hidden'
                    style={
                      key === 'actions'
                        ? { // Cột hành động: cố định chiều rộng
                            width: initialColumnsConfig.actions.width,
                            minWidth: initialColumnsConfig.actions.minWidth,
                            maxWidth: initialColumnsConfig.actions.maxWidth,
                          }
                        : {} // Cột khác: để CSS class 'column-hidden' xử lý hoặc browser tự điều chỉnh
                    }
                  >
                    {/* Xử lý định dạng ngày cho các trường ngày tháng */}
                    {['ngayThanhLap', 'ngayCapCCCD', 'issueDate', 'expiryDate'].includes(key) ?
                      (f[key] ? new Date(f[key]).toLocaleDateString() : '') :
                      (key === 'actions' ? (
                        <div className="action-buttons-cell"> {/* Ô chứa các nút hành động */}
                          <button onClick={() => handleView(f._id)} className="action-button view-button">Sổ nuôi</button>{' '}
                          <button onClick={() => handleEdit(f._id)} className="action-button edit-button">✏️</button>{' '}
                          <button onClick={() => handleDelete(f._id)} className="action-button delete-button">🗑️</button>
                        </div>
                      ) : f[key])
                    }
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default FarmListPage;
